function canPlaceBalls(force, position, m) {
    let last_position = position[0];
    let placed_balls = 1;

    for (let i = 1; i < position.length; i++) {
        if (position[i] - last_position >= force) {
            placed_balls++;
            last_position = position[i];

            if (placed_balls === m) {
                return true;
            }
        }
    }

    return false;
